 * Finds duplicate transactions (same userId + amount + date).
 *
 * Single pass with a Map keyed on userId|amount|date for O(n) grouping.
 * Groups with fewer than 2 transactions are discarded at the end.
 */
export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  const map = new Map<string, DuplicateGroup>();

  for (const t of transactions) {
    const key = `${t.userId}|${t.amount}|${t.date}`;
    const existing = map.get(key);
    if (existing) {
      existing.transactions.push(t);
    } else {
      map.set(key, { key, transactions: [t] });
    }
  }

  const result: DuplicateGroup[] = [];
  for (const group of map.values()) {
    if (group.transactions.length >= 2) result.push(group);
  }
  return result;
}

/**
 * Calculates running balance for a specific user, sorted by date.
 *
 * Single pass to collect user transactions, sort once, then one pass
 * to accumulate the running balance incrementally.
 */
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  const userTransactions: Transaction[] = [];
  for (const t of transactions) {
    if (t.userId === userId) userTransactions.push(t);
  }

  userTransactions.sort((a, b) => a.date.localeCompare(b.date));

  const entries: RunningBalanceEntry[] = [];
  let balance = 0;
  for (const t of userTransactions) {
    balance += t.amount;
    entries.push({
      transactionId: t.id,
      amount: t.amount,
      balance: Math.round(balance * 100) / 100,
      date: t.date,
    });
  }

  return entries;
}

/**
 * Returns the top N spenders.
 *
 * Single pass accumulating totals/counts into a Map, then native sort.
 */
export function topSpenders(
  transactions: Transaction[],
  n: number
): SpenderSummary[] {
  const map = new Map<string, { total: number; count: number }>();

  for (const t of transactions) {
    const existing = map.get(t.userId);
    if (existing) {
      existing.total += t.amount;
      existing.count++;
    } else {
      map.set(t.userId, { total: t.amount, count: 1 });
    }
  }

  const summaries: SpenderSummary[] = [];
  for (const [userId, { total, count }] of map) {
    summaries.push({
      userId,
      totalSpent: Math.round(total * 100) / 100,
      transactionCount: count,
    });
  }

  summaries.sort((a, b) => b.totalSpent - a.totalSpent);
  return summaries.slice(0, n);
}

/**
 * Searches transactions by description text.
 *
 * KNOWN PERFORMANCE ISSUE: Creates a new RegExp for every transaction
 * and does a linear dedup scan on the results array.
 */
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  const results: Transaction[] = [];

  for (const transaction of transactions) {
    // SLOW: Create a brand new RegExp for every transaction
    const pattern = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "i");
    const match = pattern.test(transaction.description);

    if (match) {
      // SLOW: Check if already added by scanning results array
      let alreadyAdded = false;
      for (const r of results) {
        if (r.id === transaction.id) {
          alreadyAdded = true;
          break;
        }
      }

      if (!alreadyAdded) {
        results.push(transaction);
      }
    }
  }

  return results;
}

/**
 * Runs the full processing pipeline.
 */
export function processAll(
  transactions: Transaction[],
  topN: number = 10
): PipelineResult {
  const categoryGroups = groupByCategory(transactions);
  const duplicates = findDuplicates(transactions);
  const topSpendersList = topSpenders(transactions, topN);

  return {
    categoryGroups,
    duplicates,
    topSpenders: topSpendersList,
  };
}

